576→const App = () => {
577→  const [isMobile, setIsMobile] = useState<boolean | null>(() => window.innerWidth <= 768);
578→  const [isNative, setIsNative] = useState(() => Capacitor.isNativePlatform());
579→  const [onboardingCompleted, setOnboardingCompleted] = useState<boolean | null>(true);
580→  const { setTheme } = useTheme();
581→
582→  useEffect(() => {
583→    let mounted = true;
584→
585→    const checkPlatform = async () => {
586→      // Safety Timeout: Force load if platform check hangs
587→      const timeoutId = setTimeout(() => {
588→        if (mounted) {
589→          setIsMobile(prev => prev ?? (window.innerWidth <= 768));
590→          setOnboardingCompleted(prev => prev ?? true);
591→          setIsNative(prev => prev || false);
592→        }
593→      }, 1000);
594→
595→      try {
596→        const info = await Device.getInfo();
597→        const native = info.platform === 'android' || info.platform === 'ios';
598→
599→        if (mounted) {
600→          setIsNative(native);
601→          setIsMobile(native || window.innerWidth <= 768);
602→
603→          if (native) {
604→            const { value } = await Preferences.get({ key: 'onboarding_completed' });
605→            setOnboardingCompleted(value === 'true');
606→            setTheme('dark');
607→            // Hide status bar and set overlay
608→            await StatusBar.hide();
609→            await StatusBar.setOverlaysWebView({ overlay: true });
610→            await StatusBar.setStyle({ style: Style.Dark });
611→          } else {
612→            setOnboardingCompleted(true);
613→            setTheme('light');
614→          }
615→        }
616→        clearTimeout(timeoutId);
617→      } catch (e) {
618→        setIsMobile(window.innerWidth < 768);
619→      }
620→    };
621→
622→    const handleResize = () => {
623→      if (mounted) {
624→        setIsMobile(window.innerWidth <= 768);
625→      }
626→    };
627→
628→    checkPlatform();
629→    window.addEventListener('resize', handleResize);
630→    return () => {
631→      mounted = false;
632→      window.removeEventListener('resize', handleResize);
633→    };
634→  }, []);
635→
636→  // Performance: Prefetch Pricing components to prevent flickering/white screen
637→  useEffect(() => {
638→    const prefetchPricing = async () => {
639→      try {
640→        const prefetch = [
641→          import("@/components/PricingModal"),
642→          import("./pages/Pricing"),
643→          import("./mobile/pages/MobileMockExams")
644→        ];
645→        await Promise.all(prefetch);
646→      } catch (e) {
647→        // silent fail
648→      }
649→    };
650→
651→    // Delay to allow critical rendering to complete first
652→    const t = setTimeout(prefetchPricing, 8000);
653→    return () => clearTimeout(t);
654→  }, []);
655→
656→
657→
658→
659→  if (isMobile === null) return null;
660→
661→  return (
662→    <AppProviders>
663→      <AuthBridge
664→        isNative={isNative}
665→        onboardingCompleted={onboardingCompleted}
666→        setOnboardingCompleted={setOnboardingCompleted}
667→        isMobile={isMobile}
668→      />
669→    </AppProviders>
670→  );
671→};
