674→  return (
675→    <QueryClientProvider client={queryClient}>
676→      <ThemeProvider attribute="class" defaultTheme="light" enableSystem={false}>
677→        <AuthProvider>
678→          <PricingProvider>
679→            <ExamProvider>
680→              <AIProvider>
681→                <TooltipProvider>
682→                  <LiveEditProvider>
683→                    {children}
